module bluetooth_encoder(  
    input [3:0] decoded_data,  
    input clk,  
    input reset,  
    output reg [3:0] encoded_data  
);  

always @(posedge clk or posedge reset) begin  
    if (reset)  
        encoded_data <= 4'b0000;  
    else begin  
        if (decoded_data < 4'b1000)  
            encoded_data <= decoded_data;  
        else  
            encoded_data <= decoded_data ^ 4'b1010;  
    end  
end  
endmodule
